pipeline.evaluate:
(async () => {
  const text = ${{ args.text | json }};
  let box = document.querySelector('[data-testid="tweetTextarea_0"]');

  if (!box) {
    let replyBtn = null;
    for (let attempts = 0; attempts < 20 && !replyBtn; attempts += 1) {
      replyBtn = document.querySelector('[data-testid="reply"]') || document.querySelector('[aria-label^="Reply"]');
      if (!replyBtn) await new Promise(r => setTimeout(r, 500));
    }

    if (!replyBtn) {
      return [{ status: 'failed', message: 'Could not find Reply button' }];
    }

    replyBtn.click();
    await new Promise(r => setTimeout(r, 1500));
    box = document.querySelector('[data-testid="tweetTextarea_0"]');
  }

  if (!box) {
    return [{ status: 'failed', message: 'Could not find reply text area' }];
  }

  box.focus();
  const dataTransfer = new DataTransfer();
  dataTransfer.setData('text/plain', text);
  box.dispatchEvent(new ClipboardEvent('paste', {
    clipboardData: dataTransfer,
    bubbles: true,
    cancelable: true
  }));

  await new Promise(r => setTimeout(r, 1000));

  const btn = document.querySelector('[data-testid="tweetButton"]') || document.querySelector('[data-testid="tweetButtonInline"]');
  if (btn && !btn.disabled) {
    btn.click();
    await new Promise(r => setTimeout(r, 3000));
    return [{ status: 'success', message: 'Reply posted successfully' }];
  }

  return [{ status: 'failed', message: 'Reply button disabled or not found' }];
})()
